"use strict";parserFactory.register("piaotia.com",()=>new PtwxzParser);class PtwxzParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("#content table tbody tr td table caption a").href,r=(await this.fetchChapter(t)).querySelector("div.centent");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("body")}extractTitleImpl(e){return e.querySelector("#content table table table h1")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"#guild, #shop, .toplink, table, #feit2, #Commenddiv, .bottomlink"),super.removeUnwantedElementsFromContentElement(e)}async fetchChapter(e){let t={makeTextDecoder:()=>new TextDecoder("gbk")};return(await HttpClient.wrapFetch(e,t)).responseXML}findCoverImageUrl(e){return e.querySelector("#content table table a:not([tiptitle]) img")?.src??null}}